INSERT INTO [spec_wizards] ([id], [name], [description], [expert_language_plugin], [prd], [functional_requirements], [non_functional_requirements], [persistence], [architecture], [engineering_philosophies], [design_patterns], [data_patterns], [stack_config], [business_state_management], [business_api_contract], [business_customization_details], [business_final_adjustments], [business_architecture_recommendations], [color], [icon], [architecture_health], [created_at], [updated_at], [dependency_manifest], [stack_plugin]) VALUES ('wizard-1784081043388-8y344suit', 'Local Vault', '', 'flutter-expert', 'Guardião Local – Gerenciador Seguro de Senhas e APIs1. Visão Geral do ProdutoO Guardião Local é um aplicativo desktop leve, rápido e seguro para armazenar senhas, chaves de API e tokens localmente. O foco principal é a privacidade absoluta, eliminando qualquer sincronização em nuvem não autorizada e fornecendo uma experiência de cópia e colagem instantânea.🎯 Objetivos PrincipaisSegurança Total: Armazenamento 100% local com criptografia de ponta a ponta na máquina do usuário.Velocidade: Interface minimalista com atalhos rápidos para busca e cópia de credenciais.Portabilidade: Executável único que roda nativamente no sistema operacional sem dependências pesadas.', '["RF01: Autenticação Inicial (Master Password)Descrição: O usuário deve criar uma \"Senha Mestra\" no primeiro acesso. Todas as credenciais futuras serão derivadas desta senha.Regra de Negócio: Sem a Senha Mestra, o banco de dados local torna-se ilegível. Não existe recuperação de senha (\"Esqueci minha senha\").RF02: Cadastro de CredenciaisCampos obrigatórios: Título/Nome (Ex: AWS Produção), Categoria (Senha ou Chave de API), Valor Secreto.Campos opcionais: Usuário/E-mail, URL, Notas/Tags.Segurança: O valor secreto deve vir oculto por padrão (exibido como ••••••••).RF03: Listagem, Busca e FiltrosDescrição: Tela principal contendo a barra de busca em tempo real (utilizando o gatilho hx-trigger=\"keyup delay:200ms\" do HTMX).Filtros: Filtrar rapidamente por categorias (Todas / Senhas / Chaves de API).RF04: Ação de Cópia Segura (Clipboard)Descrição: Botão de clique único ao lado de cada credencial para copiar o segredo diretamente para a área de transferência do sistema operacional.Regra de Segurança: O Wails deve acionar a API nativa de clipboard do Go. O segredo copiado deve ser limpo da área de transferência automaticamente após 30 segundos para evitar vazamentos acidentais."]', '["RNF01: Criptografia de Dados (Essencial)Algoritmo: Os dados em repouso devem ser criptografados usando AES-GCM (256 bits).Derivação de Chave: A Senha Mestra do usuário não deve ser salva. Ela deve passar por um algoritmo de hashing robusto como Argon2id ou scrypt para derivar a chave de criptografia do banco de dados.RNF02: Armazenamento LocalFormato: Armazenado em um arquivo local único (ex: JSON criptografado ou banco de dados embutido como SQLite / BadgerDB).Localização: Diretório padrão de dados do usuário do sistema operacional (~/.config/guardiao/ no Linux/macOS ou %APPDATA% no Windows).RNF03: Performance da InterfaceTempo de Resposta: Toda interação do HTMX trocando pedaços de HTML (DOM swapping) com o backend Go/Wails deve responder em menos de 50ms."]', 'nosql', '', '["KISS","DRY","SOLID","YAGNI"]', '["Adapter","Facade","Builder","Factory","Singleton","Observer","Strategy"]', '["Repository","Active Record","DAO","Entity","DTO"]', '[]', 'local', ' Stack Tecnológica e ArquiteturaPara garantir que o desenvolvimento siga a diretriz do ecossistema escolhido:Frontend: HTML5 + HTMX para interatividades e transições de tela dinâmicas sem carregar SPAs pesadas (React/Vue). TailwindCSS para estilização.Backend & Criptografia: Go (Golang) gerenciando o ciclo de vida, persistência e criptografia pesada.Ponte Desktop: Wails v2/v3 atuando como o runtime que expõe as funções seguras do Go diretamente para as requisições AJAX/HTMX da interface. 2', 'Fluxo de Experiência do Usuário (UX) proposto para HTMXTela de Bloqueio: Input de texto centrado pedindo a Senha Mestra. Ao submeter, o HTMX envia para o backend do Wails. Se correto, substitui o corpo da página pela Dashboard (hx-swap="innerHTML").Dashboard Principal:Painel esquerdo: Barra de pesquisa e lista de itens filtrados.Painel direito: Detalhes do item selecionado, botão "Copiar Usuário" e "Copiar Senha".Feedback Visual: Ao clicar em copiar, o HTMX altera temporariamente o texto do botão para "Copiado! ✅" usando transições nativas de CSS e retorna ao normal após 2 segundos.', 'teste', '', '#a855f7', '🔥', 100, '2026-07-15 02:04:03.388+00:00', '2026-07-20 00:54:55.008675525-03:00', '[{"lib":"github.com/spf13/cobra","ver":"1","mandatory":true},{"lib":"github.com/spf13/viper","ver":"2","mandatory":true},{"lib":"github.com/stretchr/testify/assert","ver":"3","mandatory":false},{"lib":"teste","ver":"1","mandatory":true}]', 'go_cli_service');
